{"code":"import json, pandas as pd
from datetime import datetime

def parse_date(s):
    if s is None:
        return None
    s = str(s).strip()
    fmts = [
        "%Y-%m-%d",
        "%Y-%m-%d %H:%M:%S",
        "%d %b %Y, %H:%M",
        "%b %d, %Y at %I:%M %p",
        "%B %d, %Y at %I:%M %p",
        "%b %d, %Y",
        "%B %d, %Y",
    ]
    for f in fmts:
        try:
            return datetime.strptime(s, f).date().isoformat()
        except Exception:
            pass
    # try pandas
    try:
        return pd.to_datetime(s, errors='coerce').date().isoformat()
    except Exception:
        return None

